import streamlit as st
import views.home as home
import views.dashboard as dashboard
import views.ml_analysis as ml_analysis
import views.llm_expert as llm_expert

st.set_page_config(
    page_title="AegisNet | SISE-OPSIE 2026",
    page_icon="assets/logo.png",
    layout="wide"
)

LOGO_B64 = ""
logo_html = f'<img src="data:image/png;base64,{LOGO_B64}" alt="AegisNet"/>' 

st.markdown("""
<style>
@import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=DM+Sans:wght@300;400;500;600&display=swap');

.stApp { background-color: #0a0e1a !important; }

[data-testid="stSidebar"] {
    background: linear-gradient(180deg, #080c16 0%, #0a0e1a 100%) !important;
    border-right: 1px solid rgba(0,212,255,0.12) !important;
}
[data-testid="stSidebar"] > div:first-child {
    padding: 0 !important;
}
[data-testid="stSidebar"] section {
    padding: 0 !important;
}
[data-testid="stSidebar"] .block-container {
    padding: 0 !important;
}
[data-testid="stSidebarContent"] {
    padding: 0 !important;
}
[data-testid="stSidebar"] > div > div > div {
    padding: 0 !important;
    gap: 0 !important;
}

.sidebar-logo {
    display: flex; flex-direction: column; align-items: center;
    padding: 0.5rem 0.5rem 0.4rem;
    border-bottom: 1px solid rgba(0,212,255,0.1);
    margin-bottom: 0.5rem;
}
.sidebar-logo img {
    width: 200px; height: 200px; object-fit: contain; margin-bottom: 0.3rem; max-width: 100%;
    filter: drop-shadow(0 0 12px rgba(0,212,255,0.5));
}
.sidebar-brand {
    font-family: 'Space Mono', monospace;
    font-size: 1.3rem; font-weight: 700; color: #00d4ff;
    letter-spacing: -0.5px; text-align: center;
}
.sidebar-tagline {
    font-family: 'DM Sans', sans-serif;
    font-size: 0.7rem; color: #4a5568;
    text-align: center; margin-top: 0.3rem; font-style: italic;
}

.nav-item {
    display: flex; align-items: center; gap: 0.6rem;
    padding: 0.45rem 0.9rem; border-radius: 8px;
    border: 1px solid transparent;
    font-family: 'DM Sans', sans-serif; font-size: 0.85rem;
    color: #6b7a99; font-weight: 500;
    transition: all 0.2s ease;
    margin: 0.02rem 0.6rem;
}
.nav-item:hover {
    background: rgba(0,212,255,0.08) !important;
    border-color: rgba(0,212,255,0.2) !important;
    color: #00d4ff !important;
    transform: translateX(3px);
}
.nav-item.active {
    background: rgba(0,212,255,0.1) !important;
    border-color: rgba(0,212,255,0.25) !important;
    color: #00d4ff !important; font-weight: 600;
}
.nav-icon { font-size: 1.1rem; width: 22px; text-align: center; }

.sidebar-footer {
    padding: 1rem 1.5rem;
    border-top: 1px solid rgba(0,212,255,0.08);
    text-align: center; margin-top: 2rem;
}
.sidebar-footer span {
    font-family: 'Space Mono', monospace;
    font-size: 0.62rem; color: #2d3748;
    letter-spacing: 0.1em; text-transform: uppercase;
}

[data-testid="stSidebar"] .stButton { margin: 0 !important; }
[data-testid="stSidebar"] .stButton > button {
    background: transparent !important;
    border: none !important; color: transparent !important;
    height: 0px !important; padding: 0 !important;
    font-size: 0 !important; min-height: 0 !important;
    width: 100% !important; cursor: pointer !important;
}
</style>
""", unsafe_allow_html=True)

PAGES = [
    ("🏠", "Accueil",                    "home"),
    ("📊", "Analyse Descriptive",        "dashboard"),
    ("🔬", "Détection d'Anomalies",      "ml_analysis"),
    ("🧠", "Assistant IA — SENTINEL",    "llm_expert"),
]

if "page" not in st.session_state:
    st.session_state["page"] = "home"

with st.sidebar:
    st.markdown(f"""
    <div class="sidebar-logo">
        {logo_html}
        <div class="sidebar-brand">AegisNet</div>
        <div class="sidebar-tagline">L'intelligence au service de la résilience.</div>
    </div>
    """, unsafe_allow_html=True)

    for icon, label, key in PAGES:
        cls = "active" if st.session_state.get("page", "home") == key else ""
        st.markdown(f"""
        <div class="nav-item {cls}">
            <span class="nav-icon">{icon}</span>
            <span>{label}</span>
        </div>
        """, unsafe_allow_html=True)
        if st.button(f"{icon} {label}", key=f"btn_{key}", use_container_width=True):
            st.session_state["page"] = key
            st.rerun()

    st.markdown("""
    <div class="sidebar-footer">
        <span>Challenge SISE·OPSIE</span>
    </div>
    """, unsafe_allow_html=True)

page = st.session_state.get("page", "home")
if page == "home":
    home.show()
elif page == "dashboard":
    dashboard.show()
elif page == "ml_analysis":
    ml_analysis.show()
elif page == "llm_expert":
    llm_expert.show()